    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            long landEnd = landStartTime[i] + landDuration[i];
            long time1 = Math.max(landEnd, waterStartTime[j]) + waterDuration[j];

            long waterEnd = waterStartTime[j] + waterDuration[j];
